TARGET := riscv64gc-unknown-none-elf
MODE := release
ifeq ($(MODE), release)
	MODE_FLAG := --release
endif

USER_APP_NAME := hello

#############################
# 	需要的一些文件路径
#############################

# RISC-V SBI
BOOTLOADER := ./bootloader/rustsbi-qemu.bin
# 内核
KERNEL_ELF := ./target/${TARGET}/${MODE}/kernel
KERNEL_BIN := ./target/${TARGET}/${MODE}/kernel.bin
# 用户态程序
USER_ELF := ./target/${TARGET}/${MODE}/${USER_APP_NAME}
USER_BIN := ./target/${TARGET}/${MODE}/${USER_APP_NAME}.bin
# 文件系统镜像
FS_IMG := ./sdcard.img

#############################
# 	命令和命令行参数
#############################
# QEMU
QEMU := qemu-system-riscv64
QEMU_FLAGS := -machine virt \
	-nographic \
	-bios ${BOOTLOADER} \
	-device loader,file=${KERNEL_BIN},addr=0x80200000 \
	-drive file=${FS_IMG},if=none,format=raw,id=x0 \
    -device virtio-blk-device,drive=x0,bus=virtio-mmio-bus.0

# ECHO：显示文字
ECHO := echo
ECHO_FLAGS := -e # 用于启用转义字符
# GDB
GDB := riscv64-unknown-elf-gdb
GDB_FLAGS := -ex 'file ${KERNEL_ELF}' \
    -ex 'set arch riscv:rv64' \
    -ex 'target remote localhost:1234'
# 用于操作二进制文件：如去除元数据
OBJCOPY := rust-objcopy



# 环境和工具安装
.PHONY: env
env:
	@rustup override set nightly
	@rustup target add riscv64gc-unknown-none-elf
	@cargo install cargo-binutils
	@rustup component add llvm-tools-preview
	@rustup component add rust-src


.DEFAULT_GOAL := run


.PHONY: clean
clean:
	@cargo clean
	@rm ./kernel-qemu
	@rm ./sbi-qemu


.PHONY: build
build:
	@cargo build --package init ${MODE_FLAG}
	@cargo build --package user ${MODE_FLAG}
	@cargo build --package kernel ${MODE_FLAG}
	@${OBJCOPY} --strip-all ${KERNEL_ELF} -O binary ${KERNEL_BIN}


.PHONY: run
run: build
	@${ECHO} ${ECHO_FLAGS} "\n[`date`] 在Qemu上开始运行，要停止运行请键入(Ctrl + A) + X\n"
	@${QEMU} ${QEMU_FLAGS}


.PHONY: debug
debug: build
	@${ECHO} ${ECHO_FLAGS} "\n[`date`] 在Qemu上开始调试，要停止运行请键入(Ctrl + A) + X"
# @${ECHO} ${ECHO_FLAGS} "[`date`] 请在其他终端中运行 make gdb\n"
	@${QEMU} ${QEMU_FLAGS} -s -S


.PHONY: gdb
gdb:
	${GDB} ${GDB_FLAGS}


.PHONY: all
all:
	@cp -r cargo .cargo
	@cargo build --package init ${MODE_FLAG}
	@cargo build --package kernel ${MODE_FLAG}
	@cp ${KERNEL_ELF}.bin ./kernel-qemu
	@cp ${BOOTLOADER} ./sbi-qemu

.PHONY: objdump
objdump:
	@rust-objdump -d ${KERNEL_ELF} > asm.txt 

