    shutdown(true);
}

/// 清空.bss段
fn clear_bss() {
    extern "C" {
        fn _sbss();
        fn _ebss();
    }
    (_sbss as usize.._ebss as usize).for_each(|b| unsafe { (b as *mut u8).write_volatile(0) });
}

