/// 伙伴系统每个空闲列表的数组长度
const BUDDY_FREE_LIST_LENGTH: usize = 100;
/// 伙伴系统的最大幂次：采用左闭右开，如果值为11则最大的连续物理内存为2^(11-1)页大小，即4MB
const BUDDY_MAX_ORDER: u8 = 11;
/// 内存的起始地址
const MEMORY_START: usize = 0x8000_0000;
/// 内存的大小
const MEMORY_SIZE: usize = 0x800_0000; // 内存大小默认为128MB
/// 页的大小
pub const PAGE_SIZE: usize = 0x1000; // 默认页大小为4KB
/// 偏移量长度
pub const PAGE_OFFSET_WIDTH: usize = 12;
/// 内核堆大小，以二进制文件中以bss段存在
const KERNEL_HEAP_SIZE: usize = 0x100_0000;
/// 跳板所在的虚拟地址
pub const TRAMPOLINE_VIRT_ADDR: usize = usize::MAX - PAGE_SIZE + 1;
/// 上下文所在的虚拟地址
pub const CONTEXT_VIRT_ADDR: usize = usize::MAX - 2 * PAGE_SIZE + 1;
/// 用户态应用的内核栈的大小
const KERNEL_STACK_SIZE: usize = 4096;
/// 用户态应用的默认栈大小
const DEFAULT_APP_STACK_SIZE: usize = 4096 * 2;

pub fn init() {
    slub::init_kernel_heap();
    virt_mem::kernel_virt_mem_space::KERNEL_VIRT_MEM_SPACE.write().set_satp();
}

/*!
 * # 伙伴系统
 * 用于管理**物理**内存，分配连续的物理内存页
 */

use super::address::{PhysAddr, PhysPageNum};
use super::{BUDDY_FREE_LIST_LENGTH, BUDDY_MAX_ORDER, MEMORY_SIZE, MEMORY_START};
use spin::{Lazy, RwLock};

/// 伙伴系统的空闲列表，该列表中物理内存块的大小都为 2^order * 4KB
#[derive(Debug)]
pub struct BuddyFreeList {
    pub order: usize, // 此空闲列表中物理页的幂次
    pub free_list: [Option<PhysPageNum>; BUDDY_FREE_LIST_LENGTH], // 根据起始物理地址和 order 就可以唯一确定一个物理内存块
    pub num: usize,                                               // 当前free_list包含的空闲块个数
}

impl BuddyFreeList {
    fn new(order: usize) -> Self {
        Self {
            order,
            num: 0,
            free_list: [None; BUDDY_FREE_LIST_LENGTH],
        }
    }

    /// 空闲列表是否为空
    fn empty(&self) -> bool {
        self.num == 0
    }

    /// 空闲列表是否为满
    fn full(&self) -> bool {
        self.num >= BUDDY_FREE_LIST_LENGTH
    }

    /// 向空闲列表中添加元素，如果空闲列表已满则返回false
    fn push(&mut self, ppn: PhysPageNum) -> bool {
        if self.full() {
            false
        } else {
            self.free_list[self.num] = Some(ppn);
            self.num += 1;
            true
        }
    }

    /// 向空闲列表中删除最后一个元素，并返回该元素
    fn pop(&mut self) -> Option<PhysPageNum> {
        if self.empty() {
            None
        } else {
            let res = self.free_list[self.num - 1];
            self.free_list[self.num - 1] = None;
            self.num -= 1;
            res
        }
    }

    /// 删除空闲列表中指定物理地址的某一元素，如果该元素不存在，则返回false
    fn remove(&mut self, ppn: PhysPageNum) -> bool {
        let mut res = false;
        for i in 0..self.num {
            if self.free_list[i].unwrap() == ppn {
                res = true;
            }

            if res {
                if i + 1 == self.num {
                    self.free_list[i] = None;
                } else {
                    self.free_list[i] = self.free_list[i + 1]
                }
            }
        }
        res
    }

    /// 判断空闲列表中是否包含某一元素
    fn contain(&self, ppn: PhysPageNum) -> bool {
        for i in 0..self.num {
            if self.free_list[i].unwrap() == ppn {
                return true;
            }
        }
        false
    }
}

/// 伙伴系统物理内存分配器
pub struct BuddyAllocator {
    pub start_ppn: PhysPageNum, // 伙伴系统所管理物理内存起始物理页号
    pub all_page_num: usize,    // 伙伴系统所管理的物理页总数量
    pub free_lists: [BuddyFreeList; BUDDY_MAX_ORDER as usize], // 空闲内存块列表数组
}

impl BuddyAllocator {
    pub fn new(start_ppn: PhysPageNum, all_page_num: usize) -> Self {
        let mut free_lists: [BuddyFreeList; BUDDY_MAX_ORDER as usize] =
            core::array::from_fn(|i| BuddyFreeList::new(i));

        // 向free_lists中填充空闲内存块数组，先填充大的，后填充小的
        let mut page_num = 0; // 当前已经放到伙伴系统的物理页数
        let mut ppn = start_ppn; // 当前正在处理的物理页号
        let mut order = all_page_num
            .ilog2() // 这里虽然后返回结果经过了四舍五入，但是由于之后和BUDDY_MAX_ORDER-1进行了比较，所以不影响结果
            .min((BUDDY_MAX_ORDER - 1) as u32); // 当前空闲块放入的空闲列表的次数
        while page_num < all_page_num {
            // let now_order = (all_page_num - page_num).ilog2();
            // if now_order < order {
            //     // 如果当前剩余的页表数不足，则向低一级插入内存块
            //     order = now_order;
            // }
            let buddy_free_list = &mut free_lists[order as usize];
            if buddy_free_list.full() {
                if order == 0 {
                    // 当前free_list已填充满
                    println!("[KERNEL] Buddy free list can't hold all memory!");
                    break;
                } else {
                    order -= 1;
                }
            } else {
                buddy_free_list.push(ppn);
                page_num += 2usize.pow(order);
                ppn = ppn + PhysPageNum::new(2usize.pow(order));
            }
        }

        Self {
            start_ppn,
            all_page_num: page_num,
            free_lists,
        }
    }

    /// 获取一个物理块的伙伴地址：翻转相应位即可
    #[inline]
    fn buddy_of(ppn: PhysPageNum, order: u8) -> PhysPageNum {
        PhysPageNum::new(ppn.get_value() ^ (1 << order))
    }

    /// 分配连续物理页
    pub fn alloc(&mut self, order: u8) -> Option<PhysPageNum> {
        if order >= BUDDY_MAX_ORDER {
            return None;
        }

        let buddy_free_list = &mut self.free_lists[order as usize];
        match buddy_free_list.pop() {
            Some(ppn) => Some(ppn),
            None => {
                // 使用递归向上一级获取物理块
                match self.alloc(order + 1) {
                    Some(ppn) => {
                        let buddy_ppn = Self::buddy_of(ppn, order); // 获取伙伴块
                        let buddy_free_list = &mut self.free_lists[order as usize];
                        buddy_free_list.push(buddy_ppn); // 将伙伴块添加到伙伴系统中
                        Some(ppn)
                    }
                    None => None,
                }
            }
        }
    }

    /// 释放连续物理页：释放失败返回false
    pub fn free(&mut self, start_ppn: PhysPageNum, order: u8) -> bool {
        if order >= BUDDY_MAX_ORDER {
            return false;
        }

        // 如果次数是伙伴系统所支持的最大的次数，则直接加入
        if order == BUDDY_MAX_ORDER - 1 {
            return self.free_lists[order as usize].push(start_ppn);
        }

        let buddy_free_list = &mut self.free_lists[order as usize];
        let buddy_ppn = Self::buddy_of(start_ppn, order);

        assert!(
            !buddy_free_list.contain(start_ppn),
            "[KERNEL] The freed block already exists!"
        );

        if buddy_free_list.contain(buddy_ppn) {
            // 如果此时伙伴系统中包含要释放块的伙伴块，则进行合并
            buddy_free_list.remove(buddy_ppn);
            return self.free(start_ppn.min(buddy_ppn), order + 1);
        } else {
            buddy_free_list.push(start_ppn);
            return true;
        }
    }

    /// 获取物理内存有关信息
    pub fn info(&self) {
        println!("start address {:x?}", self.start_ppn);
        println!("total size {} MB", self.all_page_num / 256);
        println!("{:?}", self.free_lists);
    }
}

/// 全局伙伴系统分配器
pub static BUDDY_ALLOCATOR: Lazy<RwLock<BuddyAllocator>> = Lazy::new(|| {
    extern "C" {
        fn _ekernel();
    }

    let start_pa = PhysAddr::new(_ekernel as usize);
    let end_pa = PhysAddr::new(MEMORY_START + MEMORY_SIZE);
    let start_ppn = start_pa.ceil();
    let end_ppn = end_pa.floor();
    let all_page_num = (end_ppn - start_ppn).get_value();
    RwLock::new(BuddyAllocator::new(start_ppn, all_page_num))
});

use core::alloc::Layout;

use super::KERNEL_HEAP_SIZE;

use linked_list_allocator::*;

#[global_allocator]
pub static HEAP_ALLOCATOR: LockedHeap = LockedHeap::empty();

static mut KERNEL_HEAP: [u8; KERNEL_HEAP_SIZE] = [0; KERNEL_HEAP_SIZE];

#[alloc_error_handler]
pub fn alloc_error_handler(layout: Layout) -> ! {
    panic!("Heap allocation error, layout = {:?}", layout);
}

pub fn init_kernel_heap() {
    unsafe {
        HEAP_ALLOCATOR.lock().init(KERNEL_HEAP.as_mut_ptr(), KERNEL_HEAP_SIZE);
    }
}

use core::ops::{Add, Sub};

use super::{PAGE_OFFSET_WIDTH, PAGE_SIZE};

const PA_WIDTH_SV39: usize = 56;
pub const VA_WIDTH_SV39: usize = 39;
const PPN_WIDTH_SV39: usize = PA_WIDTH_SV39 - PAGE_OFFSET_WIDTH;
const VPN_WIDTH_SV39: usize = VA_WIDTH_SV39 - PAGE_OFFSET_WIDTH;

// 类型定义
#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq, Debug)]
pub struct PhysAddr(usize);

#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq, Debug)]
pub struct VirtAddr(usize);

#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq, Debug)]
pub struct PhysPageNum(usize);

#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq, Debug)]
pub struct VirtPageNum(usize);

impl PhysAddr {
    #[inline]
    pub fn new(value: usize) -> Self {
        Self(value & ((1 << PA_WIDTH_SV39) - 1))
    }

    #[inline]
    /// 获取内部包含的值
    pub fn get_value(&self) -> usize {
        self.0
    }

    #[inline]
    /// 获取下界物理页号
    pub fn floor(&self) -> PhysPageNum {
        PhysPageNum(self.0 / PAGE_SIZE)
    }

    #[inline]
    /// 获取上界物理页号
    pub fn ceil(&self) -> PhysPageNum {
        PhysPageNum((self.0 - 1 + PAGE_SIZE) / PAGE_SIZE)
    }

    #[inline]
    /// 获取页内偏移
    pub fn offset(&self) -> usize {
        self.0 & (PAGE_SIZE - 1)
    }

    #[inline]
    /// 判断地址是否为页的边界
    pub fn is_aligned(&self) -> bool {
        self.offset() == 0
    }
}

impl VirtAddr {
    #[inline]
    pub fn new(value: usize) -> Self {
        Self(value & ((1 << VA_WIDTH_SV39) - 1))
    }

    #[inline]
    /// 获取内部包含的值
    pub fn get_value(&self) -> usize {
        self.0
    }

    #[inline]
    /// 获取MMU合法的虚拟地址表示
    pub fn get_bits(&self) -> usize {
        let va = self.0;
        match va >= (1 << (VA_WIDTH_SV39 - 1)) {
            true => va | (!((1 << VA_WIDTH_SV39) - 1)),
            false => va,
        }
    }

    #[inline]
    /// 获取下界虚拟页号
    pub fn floor(&self) -> VirtPageNum {
        VirtPageNum(self.0 / PAGE_SIZE)
    }

    #[inline]
    /// 获取上界虚拟页号
    pub fn ceil(&self) -> VirtPageNum {
        VirtPageNum((self.0 - 1 + PAGE_SIZE) / PAGE_SIZE)
    }

    #[inline]
    /// 获取页内偏移
    pub fn offset(&self) -> usize {
        self.0 & (PAGE_SIZE - 1)
    }

    #[inline]
    /// 判断地址是否为页的边界
    pub fn is_aligned(&self) -> bool {
        self.offset() == 0
    }
}

impl PhysPageNum {
    #[inline]
    pub fn new(value: usize) -> Self {
        Self(value & ((1 << PPN_WIDTH_SV39) - 1))
    }

    #[inline]
    /// 获取内部包含的值
    pub fn get_value(&self) -> usize {
        self.0
    }

    #[inline]
    /// 获取该物理页号对应的页的第一个物理地址
    pub fn get_phys_address(&self) -> PhysAddr {
        PhysAddr(self.0 << PAGE_OFFSET_WIDTH)
    }
}

impl VirtPageNum {
    #[inline]
    pub fn new(value: usize) -> Self {
        Self(value & ((1 << VPN_WIDTH_SV39) - 1))
    }

    #[inline]
    /// 获取内部包含的值
    pub fn get_value(&self) -> usize {
        self.0
    }

    #[inline]
    /// 获取在各级页表中的索引值，按照一级页表（根页表）、二级页表、三级页表顺序返回
    pub fn indices(&self) -> [usize; 3] {
        [self.0 >> 18 & 511, self.0 >> 9 & 511, self.0 & 511]
    }

    #[inline]
    /// 获取该虚拟页号对应的页的第一个虚拟地址
    pub fn get_virt_address(&self) -> VirtAddr {
        VirtAddr(self.0 << PAGE_OFFSET_WIDTH)
    }
}


// 实现加减法
impl Add for PhysAddr {
    type Output = Self;

    #[inline]
    fn add(self, other: Self) -> Self {
        Self(self.0 + other.0)
    }
}
impl Add for VirtAddr {
    type Output = Self;

    #[inline]
    fn add(self, other: Self) -> Self {
        Self(self.0 + other.0)
    }
}
impl Add for PhysPageNum {
    type Output = Self;

    #[inline]
    fn add(self, other: Self) -> Self {
        Self(self.0 + other.0)
    }
}
impl Add for VirtPageNum {
    type Output = Self;

    #[inline]
    fn add(self, other: Self) -> Self {
        Self(self.0 + other.0)
    }
}

impl Sub for PhysAddr {
    type Output = Self;

    #[inline]
    fn sub(self, other: Self) -> Self {
        Self(self.0 - other.0)
    }
}
impl Sub for VirtAddr {
    type Output = Self;

    #[inline]
    fn sub(self, other: Self) -> Self {
        Self(self.0 - other.0)
    }
}
impl Sub for PhysPageNum {
    type Output = Self;

    #[inline]
    fn sub(self, other: Self) -> Self {
        Self(self.0 - other.0)
    }
}
impl Sub for VirtPageNum {
    type Output = Self;

    #[inline]
    fn sub(self, other: Self) -> Self {
        Self(self.0 - other.0)
    }
}

use bitflags::*;

use crate::mm::{
    address::{PhysPageNum, VirtPageNum},
    phys_mem_region::{alloc, PMRType, PhysMemRegion},
};

bitflags! {
    pub struct PTEFlags: u8 {
        const V = 1 << 0;
        const R = 1 << 1;
        const W = 1 << 2;
        const X = 1 << 3;
        const U = 1 << 4;
        const G = 1 << 5;
        const A = 1 << 6;
        const D = 1 << 7;
    }
}

#[derive(Copy, Clone, Debug)]
/// 页表项
pub struct PageTableEntry(usize);

impl PageTableEntry {
    #[inline]
    pub fn new(ppn: PhysPageNum, flags: PTEFlags) -> Self {
        Self(ppn.get_value() << 10 | flags.bits() as usize)
    }

    #[inline]
    /// 获取物理页号
    pub fn get_ppn(&self) -> PhysPageNum {
        PhysPageNum::new((self.0 & ((1usize << 54) - 1)) >> 10)
    }

    #[inline]
    /// 获取页表项的标志位
    pub fn get_flags(&self) -> PTEFlags {
        PTEFlags::from_bits(self.0 as u8).unwrap()
    }

    #[inline]
    /// 页表项是否合法
    pub fn is_valid(&self) -> bool {
        self.get_flags().contains(PTEFlags::V)
    }

    #[inline]
    /// 对应的物理页是否可读
    pub fn is_readable(&self) -> bool {
        self.get_flags().contains(PTEFlags::R)
    }

    #[inline]
    /// 对应的物理页是否可写
    pub fn is_writable(&self) -> bool {
        self.get_flags().contains(PTEFlags::W)
    }

    #[inline]
    /// 对应的物理页是否可执行
    pub fn is_executable(&self) -> bool {
        self.get_flags().contains(PTEFlags::X)
    }

    #[inline]
    /// 让页表项不合法
    pub fn clear_valid(&mut self) {
        self.0 = self.0 & !1usize;
    }

    #[inline]
    /// 判断页表项是否为页节点
    pub fn is_leaf(&self) -> bool {
        self.get_flags()
            .intersects(PTEFlags::X | PTEFlags::W | PTEFlags::R)
            && self.is_valid()
    }
}

/// 页表等级，在SV39中有三级，根页表为一级页表
#[derive(Clone, Copy)]
pub enum PageTableLevel {
    Level1,
    Level2,
    Level3,
}

/// 单个页表，占据一个物理页
// #[derive(Clone)]
pub struct PageTable {
    pmr: PhysMemRegion,        // 该页表所位于的物理页
    pub level: PageTableLevel, // 该页表的等级
}

impl Clone for PageTable {
    fn clone(&self) -> Self {
        let pmr = alloc(0, PMRType::PageTable, true).unwrap(); // 分配一个物理页
        let data_slice = unsafe { core::slice::from_raw_parts(
            self.pmr.start_ppn.get_phys_address().get_value() as *const u8,
            4096,
        ) };
        pmr.write(data_slice);
        Self {
            pmr,
            level: self.level.clone(),
        }
    }
}

impl PageTable {
    pub fn new(level: PageTableLevel) -> Self {
        let pmr = alloc(0, PMRType::PageTable, true).unwrap(); // 分配一个物理页
        Self { level, pmr }
    }

    #[inline]
    /// 获取页表所在的物理页号
    pub fn get_ppn(&self) -> PhysPageNum {
        self.pmr.start_ppn
    }

    /// 根据页表等级确定传入的虚拟页号在该页表中的索引
    pub fn get_vpn_index(&self, vpn: VirtPageNum) -> usize {
        let indices = vpn.indices();
        match self.level {
            PageTableLevel::Level1 => indices[0],
            PageTableLevel::Level2 => indices[1],
            PageTableLevel::Level3 => indices[2],
        }
    }

    /// 根据传入的vpn获取页表项，内部会根据页表等级来获取索引号
    pub fn get_pte(&self, vpn: VirtPageNum) -> PageTableEntry {
        let pgt_ptr = self.get_ppn().get_phys_address().get_value() as *const PageTableEntry;
        unsafe {
            let a = pgt_ptr.add(self.get_vpn_index(vpn));
            a.read()
        }
    }

    /// 根据vpn添加页表项，即添加映射
    pub fn add_pte(&mut self, vpn: VirtPageNum, pte: PageTableEntry) {
        let pgt_ptr = self.get_ppn().get_phys_address().get_value() as *mut PageTableEntry;
        unsafe {
            pgt_ptr.add(self.get_vpn_index(vpn)).write(pte);
        }
    }

    /// 根据vpn将页表项设置为失效
    pub fn clear_pte_valid(&mut self, vpn: VirtPageNum) {
        let pgt_ptr = self.get_ppn().get_phys_address().get_value() as *mut PageTableEntry;
        unsafe {
            pgt_ptr
                .add(self.get_vpn_index(vpn))
                .as_mut()
                .unwrap()
                .clear_valid();
        }
    }
}

