/// 虚拟内存空间
#[derive(Clone)]
pub struct VirtMemSpace {
    pub root_pgt: PageTable,                    // 一级页表（根页表）
    regions: LinkedList<VirtMemRegion>,     // 虚拟内存区域链表，按照虚拟地址从小到大排序
    pgt_l2_map: BTreeMap<usize, PageTable>, // 二级页表，其key为一级页表的索引值
    pgt_l3_map: BTreeMap<usize, PageTable>, // 三级页表，其key为一级页表索引值 * 512 + 二级页表索引值

}

impl VirtMemSpace {
    pub fn new() -> Self {
        Self {
            root_pgt: PageTable::new(PageTableLevel::Level1),
            regions: LinkedList::new(),
            pgt_l2_map: BTreeMap::new(),
            pgt_l3_map: BTreeMap::new(),
        }
    }

    pub fn new_from_another(another: &Self) -> Self {
        let mut res = Self::new();
        // let mut regions = LinkedList::new();
        for item in another.regions.iter() {
            if item.vmr_type == VMRType::Context || item.vmr_type == VMRType::AppStack {
                continue;
            } else {
                // res.regions.push_back(item.clone());
                assert!(item.page_num == 1);
                let mut vmr = VirtMemRegion::new(item.start_vpn, item.page_num, item.permission, item.vmr_type, item.map_type, item.huge_page);
                // vmr.pmrs.clear();
                let a = item.pmrs.first_key_value().unwrap().1.start_ppn.get_phys_address().get_value();
                // let b = vmr.pmrs.first_key_value().unwrap().1.start_ppn.get_value();
                // assert!(a ==b);
                let src_slice = unsafe { core::slice::from_raw_parts(a as *const u8, 4096) };
                res.add_region(vmr, true, Some(src_slice));

            }   
        }
        res
    }

    /// 添加跳板区域的映射，如果is_kernel为true，则会在页表项上添加全局标志
    pub fn add_trampoline_mapping(&mut self, is_kernel: bool) {
        extern "C" {
            fn _strampoline();
        }
        let vpn = VirtAddr::new(TRAMPOLINE_VIRT_ADDR).floor();
        let ppn = PhysAddr::new(_strampoline as usize).floor();
        match is_kernel {
            true => self.add_mapping(
                vpn,
                ppn,
                false,
                VMRPermission::R | VMRPermission::X | VMRPermission::G,
            ),
            false => self.add_mapping(vpn, ppn, false, VMRPermission::R | VMRPermission::X),
        };
    }

    /// 虚拟内存区域是否与现有虚拟内存区域发生了重叠
    fn is_overlapping(&self, vmr: &VirtMemRegion) -> bool {
        for item in self.regions.iter() {
            // vmr的开始位置在现有区域的范围内，或者结束位置在现有区域的范围内则说明发生了重叠
            if vmr.start_vpn >= item.start_vpn && vmr.start_vpn < item.get_end_vpn()
                || vmr.get_end_vpn() > item.start_vpn && vmr.get_end_vpn() <= item.get_end_vpn()
            {
                return true;
            }
        }
        false
    }

    /// 插入虚拟内存区域，使得regions可以按照顺序排列
    ///
    /// 在插入过程中，如果发现有区域重叠则返回false；插入成功返回true
    fn insert_region(&mut self, vmr: VirtMemRegion) -> bool {
        match self.regions.len() {
            0 => {
                self.regions.push_back(vmr);
                true
            }
            1 => {
                let current = self.regions.front().unwrap();
                if vmr.start_vpn >= current.get_end_vpn() {
                    self.regions.push_back(vmr);
                    return true;
                } else if vmr.get_end_vpn() <= current.start_vpn {
                    self.regions.push_front(vmr);
                    return true;
                }
                false
            }
            _ => {
                // 插入位置在最后面
                if vmr.start_vpn >= self.regions.back().unwrap().get_end_vpn() {
                    self.regions.push_back(vmr);
                    return true;
                }

                // 插入位置在最前面
                if vmr.get_end_vpn() <= self.regions.front().unwrap().start_vpn {
                    self.regions.push_front(vmr);
                    return true;
                }

                // 插入位置在两个虚拟内存区域之间
                let mut iter = self.regions.iter();
                let current = iter.next().unwrap();
                let mut index = 0;
                let mut flag = false;
                while let Some(next) = iter.next() {
                    index += 1;
                    if vmr.start_vpn >= current.get_end_vpn() && vmr.get_end_vpn() <= next.start_vpn
                    {
                        flag = true;
                        break;
                    }
                }
                if flag {
                    let mut back_list = self.regions.split_off(index);
                    self.regions.push_back(vmr);
                    self.regions.append(&mut back_list);
                    return true;
                } else {
                    return false;
                }
            }
        }
    }

    /// 添加页表映射，并不负责内存块分配
    ///
    /// huge_page为true，但是实际采用了小页映射的原因：
    /// * 原来存在着合法的小页映射
    ///
    /// 返回结果为false表示添加映射失败，原因可能有：
    /// * 已经存在合法页表项，需要先删除映射
    /// * 存在大页映射，现在要添加小页映射
    pub fn add_mapping(
        &mut self,
        vpn: VirtPageNum,
        ppn: PhysPageNum,
        huge_page: bool,
        permission: VMRPermission,
    ) -> bool {
        let indices = vpn.indices();
        let leaf_flags = PTEFlags::from_bits(permission.bits()).unwrap() | PTEFlags::V; // 根页表项的标志位
                                                                                        // 进行二级页表映射
        if huge_page && indices[2] == 0 {
            match self.pgt_l2_map.get_mut(&indices[0]) {
                // 相应的二级页表已经分配
                Some(pgt_l2) => {
                    let pte_l2 = pgt_l2.get_pte(vpn);
                    if pte_l2.is_leaf() {
                        // 二级页表项已经为叶页页表项，映射添加失败
                        println!("[warning] Vaild huge page table entry has existed while adding new huge page table entry!");
                        return false;
                    } else if !pte_l2.is_valid() {
                        // 二级页表项已经无效，添加大页映射
                        pgt_l2.add_pte(vpn, PageTableEntry::new(ppn, leaf_flags));
                        return true;
                    }
                    // 二级相应页表项已经存在且不为叶页表项，添加三级映射，采用小页映射
                }
                // 相应的二级页表还没有分配
                None => {
                    let mut pgt_l2 = PageTable::new(PageTableLevel::Level2);
                    self.root_pgt
                        .add_pte(vpn, PageTableEntry::new(pgt_l2.get_ppn(), PTEFlags::V));
                    pgt_l2.add_pte(vpn, PageTableEntry::new(ppn, leaf_flags));

                    self.pgt_l2_map.insert(indices[0], pgt_l2);
                    return true;
                }
            }
        }

        // 进行三级页表映射
        match self.pgt_l2_map.get_mut(&indices[0]) {
            // 相应的二级页表已经分配
            Some(pgt_l2) => {
                let pte_l2 = pgt_l2.get_pte(vpn);
                if pte_l2.is_leaf() {
                    // 二级相应页表项已经存在且为叶页表项，映射添加失败
                    println!("[warning] Vaild huge page table entry has existed while adding new normal page table entry!");
