use core::arch::asm;

use alloc::{collections::BTreeMap, sync::Arc, vec::Vec};
use riscv::register::satp;
use spin::{Lazy, RwLock};

use crate::{driver::qemu::MMIO, mm::{
    address::VirtAddr,
    virt_mem::{
        virt_mem_region::{VMRMapType, VMRPermission, VMRType, VirtMemRegion},
        virt_mem_space::VirtMemSpace,
    },
    KERNEL_STACK_SIZE, MEMORY_SIZE, MEMORY_START, PAGE_SIZE,
}};

// 对内核虚拟内存空间的封装
pub struct KernelVirtMemSpace {
    pub vms: VirtMemSpace,                    // 内核虚拟地址空间
    kernel_stacks: BTreeMap<usize, VirtAddr>, // key为pid，value为应用分配的内核栈的上界地址
    next_kernel_stack: VirtAddr, // 已经分配的虚拟地址最小的栈上界地址的下一个分配的栈上界地址
    released_kernel_stacks: Vec<VirtAddr>, // 释放的栈上界地址集合
}

impl KernelVirtMemSpace {
    pub fn new() -> Self {
        extern "C" {
            fn _stext();
            fn _etext();
            fn _srodata();
            fn _erodata();
            fn _sdata();
            fn _edata();
            fn _sbss();
            fn _ebss();
            fn _kernel_stack_bottom();
            fn _kernel_stack_top();
            fn _ekernel();
        }
        let mut vms = VirtMemSpace::new();
        // 映射.text节
        let text_vmr = VirtMemRegion::new(
            VirtAddr::new(_stext as usize).floor(),
            VirtAddr::new(_etext as usize).ceil().get_value()
                - VirtAddr::new(_stext as usize).floor().get_value(),
            VMRPermission::R | VMRPermission::X | VMRPermission::G,
            VMRType::Text,
            VMRMapType::Identical,
            false,
        );
        vms.add_region(text_vmr, true, None);
        // 映射.rodata节
        let rodata_vmr = VirtMemRegion::new(
            VirtAddr::new(_srodata as usize).floor(),
            VirtAddr::new(_erodata as usize).ceil().get_value()
                - VirtAddr::new(_srodata as usize).floor().get_value(),
            VMRPermission::R | VMRPermission::G,
            VMRType::Rodate,
            VMRMapType::Identical,
            false,
        );
        vms.add_region(rodata_vmr, true, None);
        // 映射.data节
        let data_vmr = VirtMemRegion::new(
            VirtAddr::new(_sdata as usize).floor(),
            VirtAddr::new(_edata as usize).ceil().get_value()
                - VirtAddr::new(_sdata as usize).floor().get_value(),
            VMRPermission::R | VMRPermission::W | VMRPermission::G,
            VMRType::Data,
            VMRMapType::Identical,
            false,
        );
        vms.add_region(data_vmr, true, None);
        // 映射.bss节
        let bss_vmr = VirtMemRegion::new(
            VirtAddr::new(_sbss as usize).floor(),
            VirtAddr::new(_ebss as usize).ceil().get_value()
                - VirtAddr::new(_sbss as usize).floor().get_value(),
            VMRPermission::R | VMRPermission::W | VMRPermission::G,
            VMRType::Bss,
            VMRMapType::Identical,
            true,
        );
        vms.add_region(bss_vmr, true, None);
        // 映射内核栈，该部分用于启动
        let stack_vmr = VirtMemRegion::new(
            VirtAddr::new(_kernel_stack_bottom as usize).floor(),
            VirtAddr::new(_kernel_stack_top as usize).ceil().get_value()
                - VirtAddr::new(_kernel_stack_bottom as usize)
                    .floor()
                    .get_value(),
            VMRPermission::R | VMRPermission::W | VMRPermission::G,
            VMRType::KernelStack,
            VMRMapType::Identical,
            true,
        );
        vms.add_region(stack_vmr, true, None);
        // 映射物理内存
        let memory_vmr = VirtMemRegion::new(
            VirtAddr::new(_ekernel as usize).floor(),
            VirtAddr::new(MEMORY_START + MEMORY_SIZE).ceil().get_value()
                - VirtAddr::new(_ekernel as usize).floor().get_value(),
            VMRPermission::R | VMRPermission::W | VMRPermission::G,
            VMRType::Memory,
            VMRMapType::Identical,
            true,
        );
        vms.add_region(memory_vmr, true, None);
        // 映射跳板区域
        vms.add_trampoline_mapping(true);
        // 映射外设的MMIO
        for item in MMIO {
            let mmio_vmr = VirtMemRegion::new(
                VirtAddr::new(item.0).floor(),
                VirtAddr::new(item.0 + item.1).ceil().get_value()
                    - VirtAddr::new(item.0).floor().get_value(),
                VMRPermission::R | VMRPermission::W | VMRPermission::G,
                VMRType::MMIO,
                VMRMapType::Identical,
                false,
            );
            vms.add_region(mmio_vmr, true, None);
        }

        Self {
            vms,
            kernel_stacks: BTreeMap::new(),
            next_kernel_stack: VirtAddr::new(usize::MAX - 2 * PAGE_SIZE + 1),
            released_kernel_stacks: Vec::new(),
        }
    }

    /// 添加内核栈，返回栈上界的虚拟地址
    pub fn add_kernel_stack(&mut self, pid: usize) -> Option<VirtAddr> {
        let res = match self.released_kernel_stacks.is_empty() {
            true => {
                let res = self.next_kernel_stack;
                self.next_kernel_stack = self.next_kernel_stack - VirtAddr::new(2 * PAGE_SIZE);
                res
            }
            false => self.released_kernel_stacks.pop().unwrap(),
        };
        let stack_vmr = VirtMemRegion::new(
            VirtAddr::new(res.get_bits() - KERNEL_STACK_SIZE).floor(),
            res.ceil().get_value()
                - VirtAddr::new(res.get_bits() - KERNEL_STACK_SIZE)
                    .floor()
                    .get_value(),
            VMRPermission::R | VMRPermission::W,
            VMRType::KernelStack,
            VMRMapType::Allocated,
            false,
        );
        if self.vms.add_region(stack_vmr, true, None) {
            self.kernel_stacks.insert(pid, res);
            return Some(res);
        } else {
            self.next_kernel_stack = self.next_kernel_stack + VirtAddr::new(2 * PAGE_SIZE);
            self.released_kernel_stacks.push(res);
            return None;
        }
    }

    /// 删除内核栈，返回
    pub fn del_kernel_stack(&mut self, pid: usize) -> bool {
        match self.kernel_stacks.remove(&pid) {
            Some(va) => {
                self.released_kernel_stacks.push(va);
                // TODO: 删除映射
                true
            }
            None => false,
        }
    }

    /// 设置satp寄存器来激活该虚拟内存空间，该操作会刷新TLB
    pub fn set_satp(&mut self) {
        let ppn = self.vms.root_pgt.get_ppn();
        let mode = 8usize;
        let stap_bits = mode << 60 | ppn.get_value();
        unsafe {
            satp::write(stap_bits); // 在更改了satp一定要在之后调用要紧接着调用sfence.vma指令
            asm!("sfence.vma");
        }
    }

    /// 获取satp寄存器值
    pub fn get_satp(&self) -> usize {
        let ppn = self.vms.root_pgt.get_ppn();
        let mode = 8usize;
        mode << 60 | ppn.get_value()
    }
}

