// 对用户态应用的虚拟内存空间的封装
pub struct AppVirtMemSpace {
    pub vms: VirtMemSpace,     // 虚拟地址空间
    pub entry: VirtAddr,       // 应用的入口地址
    pub heap_start: VirtAddr,  // 堆的下界
    pub heap_size: usize,      // 堆的大小，单位为字节
    pub stack_start: VirtAddr, // 栈的上界
    pub stack_size: usize,     // 栈的大小，单位为字节
    pub asid: Option<u16>,
}

impl AppVirtMemSpace {
    pub fn new_from_another(another: &Self, asid: Option<u16>) -> Self {
        let mut vms = VirtMemSpace::new_from_another(&another.vms);
        // 映射应用栈，位于虚拟地址空间中的低半部分的最高位
        let stack_start_vpn =
            VirtAddr::new((1 << (VA_WIDTH_SV39 - 1) - 1) - DEFAULT_APP_STACK_SIZE).floor();
        let stack_end_va = VirtAddr::new(1 << (VA_WIDTH_SV39 - 1) - 1);
        let stack_end_vpn = stack_end_va.ceil();
        let stack_vmr = VirtMemRegion::new(
            stack_start_vpn,
            stack_end_vpn.get_value() - stack_start_vpn.get_value(),
            VMRPermission::R | VMRPermission::W | VMRPermission::U,
            VMRType::AppStack,
            VMRMapType::Allocated,
            true,
        );
        let (stack_pa, _) = another
            .vms
            .get_pa(stack_start_vpn.get_virt_address())
            .unwrap();
        let src_slice = unsafe {
            core::slice::from_raw_parts(stack_pa.get_value() as *const u8, another.stack_size)
        };
        vms.add_region(stack_vmr, true, Some(src_slice));
        // 映射保存上下文，即次高页
        let context_vmr = VirtMemRegion::new(
            VirtAddr::new(CONTEXT_VIRT_ADDR).floor(),
            1,
            VMRPermission::R | VMRPermission::W,
            VMRType::Context,
            VMRMapType::Allocated,
            false,
        );
        let (context_pa, _) = another
            .vms
            .get_pa(VirtAddr::new(CONTEXT_VIRT_ADDR))
            .unwrap();
        let src_slice =
            unsafe { core::slice::from_raw_parts(context_pa.get_value() as *const u8, PAGE_SIZE) };
        vms.add_region(context_vmr, true, Some(src_slice));
        // 映射跳板区域
        vms.add_trampoline_mapping(false);
        Self {
            vms,
            entry: another.heap_start,
            heap_start: another.heap_start,
            heap_size: another.heap_size,
            stack_start: another.stack_start,
            stack_size: another.stack_size,
            asid: asid,
        }
    }

    pub fn new_from_elf(elf_data: &[u8], asid: Option<u16>) -> Self {
        let mut vms = VirtMemSpace::new();

        let elf = ElfFile::new(elf_data).unwrap();
        let elf_header = elf.header;
        // 根据elf文件的魔数来判断是否为一个合法的elf
        assert_eq!(
            elf_header.pt1.magic,
            [0x7f, 0x45, 0x4c, 0x46],
            "invalid elf!"
        );
        let ph_count = elf_header.pt2.ph_count(); // 得到program header的数目
        let mut end_va = VirtAddr::new(0);
        for i in 0..ph_count {
            let program_header = elf.program_header(i).unwrap();
            if program_header.get_type().unwrap() == program::Type::Load {
                let start_va = VirtAddr::new(program_header.virtual_addr() as usize);
                end_va = VirtAddr::new(
                    (program_header.virtual_addr() + program_header.mem_size()) as usize,
                );
                let mut vmr_perm = VMRPermission::U;
                let flags = program_header.flags();
                if flags.is_read() {
                    vmr_perm |= VMRPermission::R;
                }
                if flags.is_write() {
                    vmr_perm |= VMRPermission::W;
                }
                if flags.is_execute() {
                    vmr_perm |= VMRPermission::X;
                }
                let vmr = VirtMemRegion::new(
                    start_va.floor(),
                    end_va.ceil().get_value() - start_va.floor().get_value(),
                    vmr_perm,
                    VMRType::None,
                    VMRMapType::Allocated,
                    false,
                );
                vms.add_region(
                    vmr,
                    true,
                    Some(
                        &elf.input[program_header.offset() as usize
                            ..(program_header.offset() + program_header.file_size()) as usize],
                    ),
                );
            }
        }

        // 映射应用栈，位于虚拟地址空间中的低半部分的最高位
        let stack_start_vpn =
            VirtAddr::new((1 << (VA_WIDTH_SV39 - 1) - 1) - DEFAULT_APP_STACK_SIZE).floor();
        let stack_end_va = VirtAddr::new(1 << (VA_WIDTH_SV39 - 1) - 1);
        let stack_end_vpn = stack_end_va.ceil();
        let stack_vmr = VirtMemRegion::new(
            stack_start_vpn,
            stack_end_vpn.get_value() - stack_start_vpn.get_value(),
            VMRPermission::R | VMRPermission::W | VMRPermission::U,
            VMRType::AppStack,
            VMRMapType::Allocated,
            true,
        );
        vms.add_region(stack_vmr, true, None);
        // 映射保存上下文，即次高页
        let context_vmr = VirtMemRegion::new(
            VirtAddr::new(usize::MAX - PAGE_SIZE + 1).floor() - VirtPageNum::new(1),
            1,
            VMRPermission::R | VMRPermission::W,
            VMRType::Context,
            VMRMapType::Allocated,
            false,
        );
        vms.add_region(context_vmr, true, None);
        // 映射跳板区域
        vms.add_trampoline_mapping(false);
        Self {
            vms,
            entry: VirtAddr::new(elf.header.pt2.entry_point() as usize),
            heap_start: end_va.ceil().get_virt_address(),
            heap_size: 0,
            stack_start: stack_end_va,
            stack_size: DEFAULT_APP_STACK_SIZE,
            asid: asid,
        }
    }

