/// 物理内存区域的类型
pub enum PMRType {
    PageTable,
    App,
    DMA
}

/// 物理内存区域
pub struct PhysMemRegionInner {
    pub start_ppn: PhysPageNum,
    pub order: u8,
    pub pmr_type: PMRType,
}

impl PhysMemRegionInner {
    pub fn new(start_ppn: PhysPageNum, order: u8, pmr_type: PMRType) -> Self {
        Self {
            start_ppn,
            order,
            pmr_type,
        }
    }

    /// 向物理内存区域内写入数据
    pub fn write(&self, data: &[u8]) {
        let len = self.size().min(data.len());
        let dst = self.start_ppn.get_phys_address().get_value() as *mut u8;
        unsafe { dst.copy_from(data.as_ptr(), len) };
    }

    /// 获取该物理内存区域的长度，单位是字节
    pub fn size(&self) -> usize {
        2usize.pow(self.order as u32) * PAGE_SIZE
    }
}

impl Drop for PhysMemRegionInner {
    fn drop(&mut self) {
        BUDDY_ALLOCATOR.write().free(self.start_ppn, self.order);
    }
}

/// 使用智能指针包裹的物理内存区域，从而方便共享
pub type PhysMemRegion = Arc<PhysMemRegionInner>;

/// 分配一块物理内存区域
///
/// order表示分配的次数，pmr_type表示分配的物理内存区域类型，zero表示是否对这块物理内存区域清零
pub fn alloc(order: u8, pmr_type: PMRType, zero: bool) -> Option<PhysMemRegion> {
    match BUDDY_ALLOCATOR.write().alloc(order) {
        Some(ppn) => {
            let pmr = Arc::new(PhysMemRegionInner::new(ppn, order, pmr_type));
            if zero {
                let len = pmr.size();
                let start_pa = ppn.get_phys_address().get_value() as *mut u8;
                unsafe {
                    for i in 0..len {
                        start_pa.add(i).write(0);
                    }
                }
            }
            Some(pmr)
        }
        None => None,
    }
}

/// 显式释放一块物理内存区域，当其引用计数为0时，才会真正释放；一般情况下不需要显式调用
pub fn free(pmr: PhysMemRegion) {
    drop(pmr)
}

