/// 进程状态
#[derive(Copy, Clone, PartialEq, Eq)]
pub enum ProcessStatus {
    New,        // 刚创建PCB，但此时进程的初始化还没有完成，不能执行
    Ready,      // 可以运行但是还没有被运行
    Running,    // 正在运行
    Waiting,    // 等待某一事件完成
    Zombie,     // 僵尸状态，此时虽然进程退出，但其部分资源（主要是PCB）还没有完全被释放
    Terminated, // 终止状态，全部资源被回收
}

/// 进程控制块PCB
pub struct ProcessControlBlock {
    pub pid: usize,                    // 进程标识符
    pub status: ProcessStatus,         // 进程状态
    pub kernel_context: KernelContext, // 内核态的上下文
    pub kernel_stack: VirtAddr,        // 应用内核栈的栈上界在内核虚拟地址空间中的虚拟地址
    pub vms: Box<AppVirtMemSpace>,     // 虚拟内存空间，包含页面基地址、上下文、栈、堆、入口地址
    pub parent: usize,                 // 父进程pid
    pub children: Vec<usize>,          // 子进程pid数组
    pub exit_code: usize,              // 存放进程退出码
    pub cwd: String,                   // 当前工作路径
    pub fd_table: FdTable,             // 文件描述符表
}

impl ProcessControlBlock {
    pub fn new_from_elf(pid: usize, parent_pid: usize, elf_data: &[u8], asid: Option<u16>) -> Self {
        let vms = Box::new(AppVirtMemSpace::new_from_elf(elf_data, asid));
        let kernel_stack = KERNEL_VIRT_MEM_SPACE.write().add_kernel_stack(pid).unwrap();
        Self {
            pid,
            status: ProcessStatus::Ready,
            kernel_context: KernelContext::init(kernel_stack),
            kernel_stack,
            vms,
            parent: parent_pid,
            children: Vec::new(),
            exit_code: 0,
            cwd: String::from_str("/").unwrap(),
            fd_table: FdTable::new(),
        }
    }

    pub fn new_from_another(pid: usize, another: &Self, asid: Option<u16>) -> Self {
        let vms = Box::new(AppVirtMemSpace::new_from_another(&another.vms, asid));
        let kernel_stack = KERNEL_VIRT_MEM_SPACE.write().add_kernel_stack(pid).unwrap();
        Self {
            pid,
            status: ProcessStatus::Ready,
            kernel_context: KernelContext::init(kernel_stack),
            kernel_stack,
            vms,
            parent: another.pid,
            children: Vec::new(),
            exit_code: 0,
            cwd: String::from_str("/").unwrap(),
            fd_table: another.fd_table.clone(),
        }
    }
}

impl Drop for ProcessControlBlock {
    fn drop(&mut self) {
        KERNEL_VIRT_MEM_SPACE.write().del_kernel_stack(self.pid);
    }
}

