/// 进程管理器
pub struct ProcessManager {
    pub pcbs: BTreeMap<usize, ProcessControlBlock>, // key为pid
    current_pid: usize,                             // 当前正在运行进程的pid
}

impl ProcessManager {
    pub fn new() -> Self {
        let init_elf_data = USER_APP_LOADER.read().get_elf_by_name("init").unwrap();
        let init_pcb = ProcessControlBlock::new_from_elf(INIT_PID, 0, init_elf_data, None);
        let mut pcbs = BTreeMap::new();
        pcbs.insert(INIT_PID, init_pcb);
        Self {
            pcbs,
            current_pid: INIT_PID,
        }
    }

    /// 获取当前正在运行进程的PCB的引用
    #[inline]
    pub fn get_current_pcb(&self) -> &ProcessControlBlock {
        self.pcbs.get(&self.current_pid).unwrap()
    }

    /// 获取当前正在运行进程的PCB的可变引用
    #[inline]
    pub fn get_mut_current_pcb(&mut self) -> &mut ProcessControlBlock {
        // println!("*********** current_pid {} pcbs {}", self.current_pid, self.pcbs.len());
        self.pcbs.get_mut(&self.current_pid).unwrap()
    }

    /// 获取当前正在运行进程的用户态上下文
    pub fn get_mut_current_context(&mut self) -> &'static mut Context {
        let (context_pa, _huge_page) = self
            .get_current_pcb()
            .vms
            .vms
            .get_pa(VirtAddr::new(CONTEXT_VIRT_ADDR))
            .unwrap();
        let context_ptr = context_pa.get_value() as *mut Context;
        unsafe { context_ptr.as_mut().unwrap() }
    }

    /// 获取还没有被使用的pid号
    pub fn get_free_pid(&self) -> Option<usize> {
        for i in MIN_PID..usize::MAX {
            if self.pcbs.get(&i).is_none() {
                return Some(i);
            }
        }
        None
    }

    /// 添加进程
    ///
    /// 返回该进程的pid
    pub fn add_process(
        &mut self,
        parent_pid: usize,
        elf_data: &[u8],
        asid: Option<u16>,
    ) -> Option<usize> {
        match self.get_free_pid() {
            Some(pid) => {
                let pcb = ProcessControlBlock::new_from_elf(pid, parent_pid, elf_data, asid);

                // 构造用户态上下文
                let mut context = Context::default();
                context.x[2] = pcb.vms.stack_start.get_bits(); // 设置用户态栈
                context.sepc = pcb.vms.entry.get_bits(); // 设置用户态程序第一条指令位置
                context.kernel_satp = KERNEL_VIRT_MEM_SPACE.read().get_satp();
                context.kernel_sp = pcb.kernel_stack.get_bits();
                context.trap_handle_va = trap_handler_inner as usize;

                let mut sstatus: usize;
                unsafe {
                    asm!(
                        "csrr {}, sstatus",
                        out(reg) sstatus
                    );
                }
                context.sstatus = sstatus & !(1usize << 8); // 设置sstatus的spp字段为0，表示用户态

                let (context_pa, _huge_page) = pcb
                    .vms
                    .vms
                    .get_pa(VirtAddr::new(CONTEXT_VIRT_ADDR))
                    .unwrap();
                unsafe {
                    let context_ptr = context_pa.get_value() as *mut Context;
                    *context_ptr = context;
                }
                self.pcbs.insert(pid, pcb);
                Some(pid)
            }
            None => None,
        }
    }

    /// 挑选下一个可以运行的进程
    pub fn find_next_proc(&self) -> usize {
        for (pid, pcb) in self.pcbs.iter() {
            if *pid > self.current_pid && pcb.status == ProcessStatus::Ready {
                return *pid;
            }
        }
        for (pid, pcb) in self.pcbs.iter() {
            if pcb.status == ProcessStatus::Ready {
                return *pid;
            }
        }
        shutdown(true);
    }

    /// 调度下一个进程
    ///
    /// current_status表示要设置调度之前运行进程的状态
    pub fn schedule(&mut self, current_status: ProcessStatus) {
        let next_pid = self.find_next_proc();

        self.pcbs.get_mut(&next_pid).unwrap().status = ProcessStatus::Running;
        self.get_mut_current_pcb().status = current_status;
        let current_kernel_context =
            self.get_mut_current_pcb().kernel_context.borrow_mut() as *mut KernelContext;
        let next_kernel_context =
            self.pcbs.get(&next_pid).unwrap().kernel_context.borrow() as *const KernelContext;
        // if self.current_pid != next_pid {

        // }
        self.current_pid = next_pid;
        println!("[KERNEL] SCHEDULE {}", self.current_pid);
        unsafe { _switch(current_kernel_context, next_kernel_context) }
    }

    /// 运行第一个进程
    pub fn run(&self) -> ! {
        // 构造用户态上下文
        let mut context = Context::default();
        context.x[2] = self.get_current_pcb().vms.stack_start.get_bits(); // 设置用户态栈
        context.sepc = self.get_current_pcb().vms.entry.get_bits(); // 设置用户态程序第一条指令位置
        context.kernel_satp = KERNEL_VIRT_MEM_SPACE.read().get_satp();
        context.kernel_sp = self.get_current_pcb().kernel_stack.get_bits();
        context.trap_handle_va = trap_handler_inner as usize;

        let mut sstatus: usize;
        unsafe {
            asm!(
                "csrr {}, sstatus",
                out(reg) sstatus
            );
        }
        context.sstatus = sstatus & !(1usize << 8); // 设置sstatus的spp字段为0，表示用户态

        let (context_pa, _huge_page) = self
            .get_current_pcb()
            .vms
            .vms
            .get_pa(VirtAddr::new(CONTEXT_VIRT_ADDR))
            .unwrap();
        unsafe {
            let context_ptr = context_pa.get_value() as *mut Context;
            *context_ptr = context;
        }

        jump_restore()
    }
