/// 用户态程序加载器，用于管理位于内核二进制文件中data区中包含的用户态程序
pub struct UserAppLoader {
    num: usize,               // 内核文件中包含的用户态程序数目
    names: Vec<&'static str>, // 每个用户态程序的名字
    elfs: Vec<&'static [u8]>, // 每个用户态程序的elf文件数据
}

impl UserAppLoader {
    pub fn new() -> Self {
        extern "C" {
            fn _app_num();
            fn _app_names();
            fn _app_elfs();
        }
        let app_num = unsafe { (_app_num as usize as *const usize).read() };
        let mut app_names = Vec::new();
        let mut app_elfs = Vec::new();

        for i in 0..app_num {
            let app_name_ptr = unsafe { (_app_names as usize as *const *const c_char).add(i) };
            let app_name = unsafe { CStr::from_ptr(*app_name_ptr) };
            app_names.push(app_name.to_str().unwrap());

            let app_elf_start_ptr = unsafe { (_app_elfs as usize as *const *const u8).add(i) };
            let app_elf_end_ptr = unsafe { (_app_elfs as usize as *const *const u8).add(i + 1) };
            // unsafe {
            //     println!("{:x?} {:x?}", *app_elf_start_ptr as usize, *app_elf_end_ptr as usize);
            // }
            let app_elf_len =
                unsafe { *app_elf_end_ptr } as usize - unsafe { *app_elf_start_ptr } as usize;
            // println!("len {:x#}", app_elf_len);
            let app_elf = unsafe { core::slice::from_raw_parts(*app_elf_start_ptr, app_elf_len) };
            app_elfs.push(app_elf);
        }

        Self {
            num: app_num,
            names: app_names,
            elfs: app_elfs,
        }
    }

    /// 根据程序名获取用户态程序的elf数据
    pub fn get_elf_by_name(&self, app_name: &str) -> Option<&'static [u8]> {
        for (index, name) in self.names.iter().enumerate() {
            if *name == app_name {
                return Some(self.elfs[index]);
            }
        }
        None
    }

    /// 获取应用数目
    pub fn get_num(&self) -> usize {
        self.num
    }

    pub fn info(&self) {
        println!("num {}", self.num);
        for i in &self.names {
            println!("{}", i);
        }
    }
}

