/// 系统调用
/// syscal_id表示相应系统调用的编号，args表示可以通过寄存器传递的6个系统调用参数
pub fn syscall(syscall_id: usize, args: [usize; 6]) -> isize {
    match syscall_id {
        SYSCALL_UNAME => sys_uname(args[0] as *mut UtsName) as isize,
        SYSCALL_GETTIMEOFDAY => {
            sys_gettimeofday(args[0] as *mut TimeVal, args[1] as *mut TimeZone) as isize
        }
        // 内存管理相关
        SYSCALL_BRK => sys_brk(VirtAddr::new(args[0])) as isize,
        SYSCALL_MUNMAP => sys_munmap(VirtAddr::new(args[0]), args[1]) as isize,
        SYSCALL_MMAP => sys_mmap(
            VirtAddr::new(args[0]),
            args[1],
            MmapProt::from_bits(args[2] as i32).unwrap(),
            MmapFlags::from_bits(args[3] as i32).unwrap(),
            args[4] as i32,
            args[5],
        ) as isize,
        // 进程管理相关
        SYSCALL_EXIT => sys_exit(args[0] as i32) ,
        SYSCALL_NANOSLEEP => {
            sys_nanosleep(args[0] as *const TimeSpec, args[1] as *mut TimeSpec) as isize
        }
        SYSCALL_SCHED_YIELD => sys_sched_yield() as isize,
        SYSCALL_TIMES => sys_times(args[0] as *mut Tms),
        SYSCALL_GETPID => sys_getpid() as isize,
        SYSCALL_GETPPID => sys_getppid() as isize,
        SYSCALL_CLONE => {
            // println!("clone {}", args[0]);
        sys_clone(
            CloneFlags::from_bits(args[0]).unwrap(),
            args[1] as *mut u8,
            args[2] as i32,
            args[3] as i32,
            args[4],
        )},
        SYSCALL_EXECVE => sys_execve(
            args[0] as *const u8,
            args[1] as *const *const u8,
            args[2] as *const *const u8,
        ) as isize,
        SYSCALL_WAIT4 => sys_wait4(
            args[0] as i32,
            args[1] as *mut i32,
            args[2] as i32,
            args[3] as *mut u8,
        ) as isize,
        // 文件系统相关
        SYSCALL_GETCWD => sys_getcwd(args[0] as *const u8, args[1]) as isize,
        SYSCALL_DUP => sys_dup(args[0] as i32) as isize,
        SYSCALL_DUP3 => sys_dup3(args[0] as i32, args[1] as i32, args[2] as i32) as isize,
        SYSCALL_MKDIRAT => {
            sys_mkdirat(args[0] as i32, args[1] as *const u8, args[2] as u32) as isize
        }
        SYSCALL_UNLINKAT => {
            sys_unlinkat(args[0] as i32, args[1] as *const u8, args[2] as i32) as isize
        }
        SYSCALL_LINKAT => sys_linkat(
            args[0] as i32,
            args[1] as *const u8,
            args[2] as i32,
            args[3] as *const u8,
            args[4] as i32,
        ) as isize,
        SYSCALL_UMOUNT2 => sys_umount2(args[0] as *const u8, args[1] as i32) as isize,
        SYSCALL_MOUNT => sys_mount(
            args[0] as *const u8,
            args[1] as *const u8,
            args[2] as *const u8,
            args[3],
            args[4] as *const u8,
        ) as isize,
        SYSCALL_CHDIR => sys_chdir(args[0] as *const u8) as isize,
        SYSCALL_OPENAT => sys_openat(
            args[0] as i32,
            args[1] as *const u8,
            OpenatFlags::from_bits(args[2] as i32).unwrap(),
            args[3] as i32,
        ) as isize,
        SYSCALL_CLOSE => sys_close(args[0] as i32) as isize,
        SYSCALL_PIPE2 => sys_pipe2(args[0] as *mut i32, args[1] as i32) as isize,
        SYSCALL_GETDENTS64 => sys_getdents64(args[0] as i32, args[1] as *mut u8, args[2]),
        SYSCALL_READ => sys_read(args[0] as i32, args[1] as *mut u8, args[2]),
        SYSCALL_WRITE => sys_write(args[0] as i32, args[1] as *const u8, args[2]),
        SYSCALL_FSTAT => sys_fstat(args[0] as i32, args[1] as *mut u8) as isize,
        _ => panic!("Unsupported syscall_id: {}", syscall_id),
    }
}

