/// 获取进程的当前工作目录的绝对路径
///
/// 失败返回空指针
pub fn sys_getcwd(buf: *const u8, size: usize) -> *const u8 {
    let cwd = PROCESS_MANAGER.read().get_current_pcb().cwd.clone();
    if buf.is_null() || size < cwd.len() + 1 {
        return core::ptr::null();
    } else {
        let cwd = CString::new(cwd).unwrap();
        let cwd = cwd.as_bytes_with_nul();
        PROCESS_MANAGER
            .write()
            .get_mut_current_pcb()
            .vms
            .write_byte_array(
                PhysAddr::new(cwd.as_ptr() as usize),
                VirtAddr::new(buf as usize),
                cwd.len(),
            );
        return buf;
    }
}

/// 复制文件描述符
///
/// 成功执行，返回新的文件描述符，否则返回-1
pub fn sys_dup(fd: i32) -> i32 {
    let mut binding = PROCESS_MANAGER.write();
    let mut fd_table = &mut binding.get_mut_current_pcb().fd_table;
    if let Some(file) = fd_table.get_ref(fd as usize).cloned() {
        let newfd = fd_table.alloc_fd();
        fd_table.put(newfd, file);
        newfd as i32
    } else {
        -1
    }
}

/// 复制文件描述符，并指定了新的文件描述符
///
/// 成功执行，返回新的文件描述符，否则返回-1
pub fn sys_dup3(oldfd: i32, newfd: i32, flags: i32) -> i32 {
    let mut binding = PROCESS_MANAGER.write();
    let mut fd_table = &mut binding.get_mut_current_pcb().fd_table;
    if let Some(file) = fd_table.get(oldfd as usize) {
        if fd_table.take(newfd as usize).is_none() {
            fd_table.alloc_spec_fd(newfd as usize);
        }
        fd_table.put(newfd as usize, file);
        newfd as i32
    } else {
        -1
    }
}

pub const AT_FDCWD: i32 = -100;

/// 创建目录
///
/// 如果path是相对路径，则它是相对于dirfd目录而言的。
/// 如果path是相对路径，且dirfd的值为AT_FDCWD，则它是相对于当前路径而言的。
/// 如果path是绝对路径，则dirfd被忽略。
///
/// 成功执行，返回0，否则返回-1
pub fn sys_mkdirat(dirfd: i32, path: *const u8, mode: u32) -> i32 {
    // TODO: 路径跨页
    let path = PROCESS_MANAGER
        .read()
        .get_current_pcb()
        .vms
        .vms
        .get_pa(VirtAddr::new(path as usize))
        .unwrap()
        .0
        .get_value() as *const u8;
    let absolute_path;
    if dirfd == AT_FDCWD {
        absolute_path = Path::path_process(path).unwrap();
    } else {
        absolute_path = Path::path_with_dirfd(dirfd as isize, path).unwrap();
    }
    let _find_inode = <dyn Inode>::lookup_from_root_tmp(&absolute_path);
    match _find_inode {
        Some(_find_inode) => -1,
        None => {
            let parent = Path::get_parent_dir(&absolute_path).unwrap();
            let parent_inode = <dyn Inode>::lookup_from_root_tmp(&parent);
            match parent_inode {
                Some(parent_inode) => match parent_inode.metadata().mode {
                    InodeMode::FileDIR => {
                        parent_inode.metadata().inner.lock().st_atime =
                            (get_microsecond() / 1000) as i64;
                        parent_inode.metadata().inner.lock().st_mtime =
                            (get_microsecond() / 1000) as i64;
                        parent_inode.mkdir(
                            parent_inode.clone(),
                            &Path::get_name(&absolute_path),
                            InodeMode::FileDIR,
                        );
                        0
                    }
                    _ => {
                        return -1;
                    }
                },
                None => -1,
            }
        }
    }
}

/// 移除指定文件的链接，可用于删除文件
///
/// 如果path是相对路径，则它是相对于dirfd目录而言的。
/// 如果path是相对路径，且dirfd的值为AT_FDCWD，则它是相对于当前路径而言的。
/// 如果path是绝对路径，则dirfd被忽略。
///
/// flags可设置为0或AT_REMOVEDIR
///
/// 成功执行，返回0，否则返回-1
pub fn sys_unlinkat(dirfd: i32, path: *const u8, flags: i32) -> i32 {
    // TODO: 路径跨页
    let path = PROCESS_MANAGER
        .read()
        .get_current_pcb()
        .vms
        .vms
        .get_pa(VirtAddr::new(path as usize))
        .unwrap()
        .0
        .get_value() as *const u8;
    let absolute_path;
    if dirfd == AT_FDCWD {
        absolute_path = Path::path_process(path).unwrap();
    } else {
        absolute_path = Path::path_with_dirfd(dirfd as isize, path).unwrap();
    }
    let target_inode = <dyn Inode>::lookup_from_root_tmp(&absolute_path);
    match target_inode {
        Some(target_inode) => {
            if target_inode.metadata().mode == InodeMode::FileDIR {
                // debug!("target_inode is dir");
                return -1;
            } else {
                let parent = target_inode.metadata().inner.lock().parent.clone();
                match parent {
                    Some(parent) => {
                        let parent = parent.upgrade().unwrap();
                        // debug!("Have a parent: {}", parent.metadata().path);
                        parent.unlink(target_inode);
                        return 0;
                    }
                    None => {
                        // debug!("Have no parent, this inode is a root node which cannot be unlink");
                        -1
                    }
                }
            }
        }
        None => -1,
    }
}

