/// 触发进程终止，无返回值
pub fn sys_exit(exit_code: i32) -> isize{
    // println!("[KERNEL] App exited with code {}", exit_code);
    let mut binding = PROCESS_MANAGER.write();
    binding.get_mut_current_pcb().exit_code = exit_code as usize;
    binding.schedule(ProcessStatus::Zombie);
    // 将当前进程的所有子进程挂在初始进程 initproc 下面，其做法是遍历每个子进程，修改其父进程为初始进程，并加入初始进程的孩子向量中
    0
}

/// 执行线程睡眠
///
/// 成功返回0，失败返回-1
pub fn sys_nanosleep(req: *const TimeSpec, rem: *mut TimeSpec) -> i32 {
    let req = PROCESS_MANAGER
        .read()
        .get_current_pcb()
        .vms
        .vms
        .get_pa(VirtAddr::new(req as usize))
        .unwrap()
        .0
        .get_value() as *const TimeSpec;
    let req = unsafe { &*req };
    let sleep_ms = req.sec * 1000 + req.nsec / 1000000;
    let start_ms = get_microsecond();
    let end_ms = sleep_ms + start_ms;

    loop {
        let now_ms = get_microsecond();
        if now_ms >= end_ms {
            return 0;
        }
        PROCESS_MANAGER.write().schedule(ProcessStatus::Ready);
    }
}

/// 让出调度器
///
/// 成功返回0，失败返回-1
pub fn sys_sched_yield() -> i32 {
    PROCESS_MANAGER.write().schedule(ProcessStatus::Ready);
    0
}

