/// 获取进程时间
///
/// ```
/// struct tms {
///     clock_t tms_utime;  /* user time */
///     clock_t tms_stime;  /* system time */
///     clock_t tms_cutime; /* user time of children */
///     clock_t tms_cstime; /* system time of children */
/// };
/// ```
///
/// 成功返回已经过去的滴答数，失败返回-1
pub fn sys_times(tms: *mut Tms) -> isize {
    let tms = PROCESS_MANAGER
        .read()
        .get_current_pcb()
        .vms
        .vms
        .get_pa(VirtAddr::new(tms as usize))
        .unwrap()
        .0
        .get_value() as *mut Tms;
    let tms = unsafe { &mut *tms };
    tms.stime = 1;
    tms.utime = 1;
    tms.cstime = 1;
    tms.cutime = 1;
    get_microsecond() as isize
}

