/// 创建一个子进程
///
/// * flags: 创建的标志，如SIGCHLD；
/// * stack: 指定新进程的栈，可为0；
/// * ptid: 父线程ID；
/// * tls: TLS线程本地存储描述符；
/// * ctid: 子线程ID；
///
/// 成功则返回子进程的线程ID，失败返回-1
pub fn sys_clone(flags: CloneFlags, stack: *mut u8, ptid: i32, ctid: i32, tls: usize) -> isize {
    // let clone_flags = {
    //     // TODO: This is just a workaround for preliminary test
    //     if flags == Signal::SIGCHLD as usize {
    //         CloneFlags::from_bits(0).unwrap()
    //     } else {
    //         clone_flags.unwrap()
    //     }
    // };
    let mut binding = PROCESS_MANAGER.write();
    let cpid = binding.get_free_pid().unwrap();
    let cpcb = ProcessControlBlock::new_from_another(cpid, binding.get_current_pcb(), None);

    let (child_context, _huge_page) = cpcb
        .vms
        .vms
        .get_pa(VirtAddr::new(CONTEXT_VIRT_ADDR))
        .unwrap();
    let (parent_context, _) = binding
        .get_current_pcb()
        .vms
        .vms
        .get_pa(VirtAddr::new(CONTEXT_VIRT_ADDR))
        .unwrap();
    unsafe {
        let mut child_context_ptr = child_context.get_value() as *mut Context;
        // println!(
        //     "parent context ptr {:x?}",
        //     parent_context.get_value() as usize
        // );
        let parent_context = *(parent_context.get_value() as *const Context);
        // println!("child context ptr {:x?}", child_context_ptr as usize);
        let mut child_context = *child_context_ptr;
        // println!("sepc {:x?} {:x?} satp {:x?}", child_context.sepc, parent_context.sepc, cpcb.vms.get_satp());
        child_context.x[10] = 0; // 子进程的返回值为0
    }
    // println!("clone satp {:x?}", cpcb.vms.get_satp());
    binding.pcbs.insert(cpid, cpcb);

    binding.get_mut_current_pcb().children.push(cpid);
    cpid as isize
}

