    let path = PROCESS_MANAGER
        .read()
        .get_current_pcb()
        .vms
        .vms
        .get_pa(VirtAddr::new(path as usize))
        .unwrap()
        .0
        .get_value() as *const u8;
    if let Some(app_inode) =
        crate::fs::fat32_tmp::open_file(&c_str_to_string(path), OpenFlags::RDONLY)
    {
        let elf_data = app_inode.read_all();
        let mut binding = PROCESS_MANAGER.write();
        let mut pcb = binding.get_mut_current_pcb();
        pcb.vms = Box::new(AppVirtMemSpace::new_from_elf(&elf_data, None));
        let kernel_stack = KERNEL_VIRT_MEM_SPACE
            .write()
            .add_kernel_stack(pcb.pid)
            .unwrap();
        pcb.kernel_stack = kernel_stack;
        return 0;
        // current_process().exec(&elf_data, args_vec, envs_vec)
    } else {
        return -1;
    }
    // 0
}

