bitflags! {
    ///Open file flags
    pub struct OpenFlags: u32 {
        ///Read only
        const RDONLY = 0;
        ///Write only
        const WRONLY = 1 << 0;
        ///Read & Write
        const RDWR = 1 << 1;
        ///Allow create
        const CREATE = 1 << 6;
        ///Clear file and return an empty one
        const TRUNC = 1 << 10;
        ///Directory
        const DIRECTORY = 1 << 21;
    }

    /// stat flags
    pub struct StatFlags: u32 {
        const AT_EMPTY_PATH = 1 << 0;
        const AT_NO_AUTOMOUNT = 1 << 11;
        const AT_SYMLINK_NOFOLLOW = 1 << 8;
    }
}

impl OpenFlags {
    /// Do not check validity for simplicity
    /// Return (readable, writable)
    pub fn read_write(&self) -> (bool, bool) {
        if self.is_empty() {
            (true, false)
        } else if self.contains(Self::WRONLY) {
            (false, true)
        } else {
            (true, true)
        }
    }
}

impl From<VMRPermission> for OpenFlags {
    fn from(perm: VMRPermission) -> Self {
        let mut res = OpenFlags::from_bits(0).unwrap();
        if perm.contains(VMRPermission::R) && perm.contains(VMRPermission::W) {
            res |= OpenFlags::RDWR;
        } else if perm.contains(VMRPermission::R) {
            res |= OpenFlags::RDONLY;
        } else if perm.contains(VMRPermission::W) {
            res |= OpenFlags::WRONLY;
        }
        res
    }
}

