            //     let src = &data_block[start % BLOCK_SZ..start % BLOCK_SZ + block_read_size];
            //     dst.copy_from_slice(src);
            // });
            read_size += block_read_size;
            // move to next block
            if end_current_block == end {
                break;
            }
            start_block += 1;
            start = end_current_block;
        }
        self.offset += read_size;
        // print!("\tdata ");
        // for i in buf {
