/// 获取mtime的值
fn get_mtime() -> usize {
    time::read()
}

/// 时钟频率，单位为Hz，是一个平台相关的值
pub const CLOCK_FREQUENCY: usize = 12500000;

/// 设置时钟中断，参数times_per_sec表示每秒发生中断的次数
pub fn set_timer_interrupt(times_per_sec: usize) {
    set_mtimecmp((get_mtime() + CLOCK_FREQUENCY / times_per_sec) as u64);
}

/// 获取微秒值
pub fn get_microsecond() -> usize {
    get_mtime() / (CLOCK_FREQUENCY / 1_000_000)
}

/// Used for nanosleep
#[derive(Clone, Copy, Debug)]
#[repr(C)]
pub struct TimeSpec {
    pub sec: usize,
    pub nsec: usize,
}

impl TimeSpec {
    pub fn new() -> Self {
        // new a time spec with machine time
        let current_time = get_microsecond() / 1000;
        Self {
            sec: current_time / 1000,
            nsec: current_time % 1000000 * 1000000,
        }
    }
}

