const FD_STDOUT: i32 = 1;

pub fn sys_write(fd: i32, buf: *const u8, count: usize) -> isize {
    match fd {
        FD_STDOUT => {
            // let user_app = USER_APP.read();
            // let vms = user_app.get_current_vms();
            let buffers = PROCESS_MANAGER
                .read()
                .get_current_pcb()
                .vms
                .translate_byte_array(VirtAddr::new(buf as usize), count);

            for buffer in buffers {
                let str = core::str::from_utf8(buffer).unwrap();
                print!("{}", str);
            }
            count as isize
        }
        _ => {
            panic!("Unsupported fd in sys_write!");
        }
    }
}

