/// 如果path是绝对路径，则dirfd被忽略。
///
/// 成功执行，返回0，否则返回-1
pub fn mkdirat(dirfd: i32, path: &CStr, mode: u32) -> i32 {
    syscall(
        SYSCALL_MKDIRAT,
