/// 如果path是绝对路径，则dirfd被忽略。
///
/// flags可设置为0或AT_REMOVEDIR
///
/// 成功执行，返回0，否则返回-1
pub fn sys_unlinkat(dirfd: i32, path: &CStr, flags: i32) -> i32 {
    syscall(
