/// 获取目录的条目
///
/// buf：一个缓存区，用于保存所读取目录的信息，其结构如下：
///
/// ```
/// struct linux_dirent64 {
///     ino64_t        d_ino;    /* 64-bit inode number */
///     off64_t        d_off;    /* 64-bit offset to next structure */
///     unsigned short d_reclen; /* Size of this dirent */
///     unsigned char  d_type;   /* File type */
///     char           d_name[]; /* Filename (null-terminated) */
/// };
/// ```
///
/// 成功执行，返回读取的字节数。当到目录结尾，则返回0。失败，则返回-1
pub fn sys_getdents64(fd: i32, buf: *mut u8, len: usize) -> isize {
    syscall(
        SYSCALL_GETDENTS64,
        [fd as usize, buf as usize, len, 0, 0, 0],
    )
}

/// 从文件或其他输入流中读取数据
///
/// fd为文件描述符，buf为缓存区
///
/// 返回值：成功时，返回读入的字节数；失败时，返回-1
pub fn read(fd: i32, buf: &mut [u8]) -> isize {
    syscall(
        SYSCALL_READ,
        [fd as usize, buf.as_mut_ptr() as usize, buf.len(), 0, 0, 0],
    )
}

/// 将数据写入文件中或其他输出流中
///
/// fd为文件描述符，buf为要写入的数据
///
/// 返回值：成功时，返回写入的字节数；失败时，返回-1
pub fn write(fd: i32, buf: &[u8]) -> isize {
    syscall(
        SYSCALL_WRITE,
        [fd as usize, buf.as_ptr() as usize, buf.len(), 0, 0, 0],
    )
}

/// 获取文件状态
///
/// ```
/// struct kstat {
