/// 	dev_t st_rdev;
/// 	unsigned long __pad;
/// 	off_t st_size;
/// 	blksize_t st_blksize;
/// 	int __pad2;
/// 	blkcnt_t st_blocks;
/// 	long st_atime_sec;
/// 	long st_atime_nsec;
/// 	long st_mtime_sec;
/// 	long st_mtime_nsec;
/// 	long st_ctime_sec;
/// 	long st_ctime_nsec;
/// 	unsigned __unused[2];
/// };
/// ```
///
/// 成功返回0，失败返回-1
pub fn sys_fstat(fd: i32, buf: *mut u8) -> i32 {
    syscall(SYSCALL_FSTAT, [fd as usize, buf as usize, 0, 0, 0, 0]) as i32
}

