/// 创建一个子进程
///
/// * flags: 创建的标志，如SIGCHLD；
/// * stack: 指定新进程的栈，可为0；
/// * ptid: 父线程ID；
/// * tls: TLS线程本地存储描述符；
/// * ctid: 子线程ID；
///
/// 成功则返回子进程的线程ID，失败返回-1
pub fn clone(flags: CloneFlags, stack: *mut u8, ptid: i32, ctid: i32, tls: usize) -> isize {
    syscall(
        SYSCALL_CLONE,
        [
            flags.bits(),
            stack as usize,
            ptid as usize,
            ctid as usize,
            tls,
            0,
        ],
    )
}

/// 创建子进程
///
/// 执行成功在父进程中返回子进程的pid，子进程中返回0；执行失败返回-1
pub fn fork() -> isize {
    syscall(SYSCALL_CLONE, [0, 0, 0, 0, 0, 0])
}

/// 等待子进程终止或停止
///
/// * pid > 0，等待pid子进程；pid = -1，等待所有子进程中的任意一个
/// * status用于保存子进程的返回值
/// *
pub fn waitpid(pid: isize, status: &mut i32, options: i32) -> isize {
    syscall(
        SYSCALL_WAIT4,
        [
            pid as usize,
            status.borrow_mut() as *mut i32 as usize,
            options as usize,
            0,
            0,
            0,
        ],
    )
}

/// 在当前进程的上下文中加载并运行一个新进程
///
/// filepath是可执行文件的路径；argv是参数列表，通常`argv[0]`是可执行文件名；
/// envp是环境变量列表，每个串都是形如“name=value”的键值对
///
/// 如果成功则不返回，如果错误则返回-1
pub fn execve(filepath: &CStr, argv: &[&CStr], envp: &[&CStr]) -> i32 {
    syscall(
        SYSCALL_EXECVE,
        [
            filepath.as_ptr() as usize,
            argv.as_ptr() as usize,
            envp.as_ptr() as usize,
            0,
            0,
            0,
        ],
    ) as i32
}

/// 执行程序
pub fn exec(filepath: &CStr) -> i32 {
    syscall(SYSCALL_EXECVE, [filepath.as_ptr() as usize, 0, 0, 0, 0, 0]) as i32
}

/// 等待进程改变状态
///
/// * pid: 指定进程ID，可为-1等待任何子进程；
/// * status: 接收状态的指针；
/// * options: 选项：WNOHANG，WUNTRACED，WCONTINUED；
///
/// 成功则返回进程ID；如果指定了WNOHANG，且进程还未改变状态，直接返回0；失败则返回-1
pub fn wait4(pid: i32, status: *mut i32, options: i32, rusage: *mut u8) -> i32 {
    syscall(
        SYSCALL_WAIT4,
        [
            pid as usize,
            status as usize,
            options as usize,
            rusage as usize,
            0,
            0,
        ],
    ) as i32
}

