#[derive(Clone, PartialEq)]
pub struct HashName {
    pub name_hash: u64,
    pub parent: usize,
    pub name: Arc<str>,
}

#[derive(Default)]
struct MyHasher(u64);

impl Hasher for MyHasher {
    fn write(&mut self, bytes: &[u8]) {
        const MUL: u64 = 130923192384972381;
        const ADD: u64 = 410934879347345269;
        self.0 = bytes.iter().copied().fold(self.0, |x, a| {
            x.wrapping_add((a as u64).wrapping_mul(MUL))
                .wrapping_add(ADD)
        });
    }
    fn finish(&self) -> u64 {
        self.0
    }
}

impl HashName {
    pub fn str2num(name: &str) -> u64 {
        BuildHasherDefault::<MyHasher>::default().hash_one(name)
    }
    pub fn myhash(base: u64, name: u64) -> u64 {
        base.rotate_left(32).wrapping_add(name)
    }
    pub fn hash_name(parent: Option<usize>, name: &str) -> HashName {
        let parent_ptr = match parent {
            Some(p) => p as u64,
            None => 0 as u64,
        };
        HashName {
            name_hash: Self::myhash(parent_ptr, Self::str2num(name)),
            parent: parent_ptr as usize,
            name: Arc::from(name),
        }
    }
    pub fn all_same(&self, other: &Self) -> bool {
        unsafe {
            if self.name_hash != other.name_hash {
                return false;
            }
        }
        if self.parent != other.parent {
            return false;
        }
        if self.name != other.name {
            return false;
        }
        return true;
    }
    pub fn name_same(&self, name_hash: u64, name: &str) -> bool {
        unsafe {
            if self.name_hash != name_hash {
                return false;
            }
        }
        if *self.name != *name {
            return false;
        }
        return true;
    }
}

impl Hashable for HashName {
    // you should call hash_name first
    fn hash(&self) -> usize {
        self.name_hash as usize
    }
}

use alloc::vec;
use alloc::{string::String, vec::Vec};

pub trait Hashable {
    fn hash(&self) -> usize;
}

impl Hashable for String {
    // http://www.cse.yorku.ca/~oz/hash.html
    fn hash(&self) -> usize {
        let mut result: usize = 5381;
        for c in self.bytes() {
            result = ((result << 5).wrapping_add(result)).wrapping_add(c.into());
        }
        result
    }
}

impl Hashable for usize {
    fn hash(&self) -> usize {
        *self
    }
}

#[derive(Clone)]
struct HashCell<Key, Value> {
    key: Key,
    value: Option<Value>,
}

pub struct HashTable<Key, Value> {
    cells: Vec<HashCell<Key, Value>>,
    taken_count: usize,
}

impl<Key, Value> HashTable<Key, Value>
where
    Key: Clone + Default + PartialEq + Hashable,
    Value: Clone,
{
    pub fn new() -> Self {
        const INITIAL_CAPACITY: usize = 13;
        let ret = Self {
            // cells: Vec::with_capacity(INITIAL_CAPACITY),
            cells: vec![
                HashCell {
                    key: Key::default(),
                    value: None,
                };
                INITIAL_CAPACITY
            ],
            taken_count: 0,
        };
        // debug!("hash table capacity {}", ret.cells.len());
        ret
    }

    pub fn extend(&mut self) {
        assert!(self.cells.len() > 0);
        let mut new_self = Self {
            cells: Vec::with_capacity(self.cells.len() * 2 + 1),
            taken_count: 0,
        };

        for cell in self.cells.iter() {
            if cell.value.is_some() {
                new_self.insert(cell.key.clone(), cell.value.clone().unwrap());
            }
        }

        *self = new_self;
    }

    pub fn insert(&mut self, key: Key, new_value: Value) {
        if let Some(old_value) = self.get_mut(&key) {
            *old_value = new_value;
        } else {
            if self.taken_count >= self.cells.len() {
                self.extend();
            }
            assert!(self.taken_count < self.cells.len());

            let mut index = key.hash() % self.cells.len();

            while self.cells[index].value.is_some() {
                index = (index + 1) % self.cells.len();
            }

            self.cells[index].key = key;
            self.cells[index].value = Some(new_value);
            self.taken_count += 1;
        }
    }

    pub fn delete(&mut self, key: Key) {
        if let Some(index) = self.get_index(&key) {
            self.cells[index].value.take();
        }
    }

    fn get_index(&self, key: &Key) -> Option<usize> {
        let mut index = key.hash() % self.cells.len();
        for _ in 0..self.cells.len() {
            if !self.cells[index].value.is_some() {
                break;
            }

            if self.cells[index].key == *key {
                break;
            }

            index = (index + 1) % self.cells.len();
        }

        if self.cells[index].value.is_some() && self.cells[index].key == *key {
            Some(index)
        } else {
            None
        }
    }

    #[allow(dead_code)]
    pub fn get(&self, key: &Key) -> Option<&Value> {
        if let Some(index) = self.get_index(key) {
            self.cells[index].value.as_ref()
            // Some(&self.cells[index].value)
        } else {
            None
        }
    }

    pub fn get_mut(&mut self, key: &Key) -> Option<&mut Value> {
        if let Some(index) = self.get_index(key) {
            self.cells[index].value.as_mut()
            // Some(&mut self.cells[index].value)
        } else {
            None
        }
    }
}

