**地址空间标识 (ASID)**: 已实现支持

```rust
pub fn set_satp(&mut self) {
    let ppn = self.vms.root_pgt.get_ppn();
    let mode = 8usize;
    let stap_bits = match self.asid {
        Some(asid) => mode << 60 | (asid as usize) << 44 | ppn.get_value(),
        None => mode << 60 | ppn.get_value(),
    };
    unsafe {
        satp::write(stap_bits);
        asm!("sfence.vma");
    }
}
```

