#### 3.5.1 跳板机制

**跳板汇编** (kernel/src/trap/trap_handler.asm):

```asm
.section .text.trampoline
.global _trap_handler
.global _restore

_trap_handler:
    # 交换 sp 和 sscratch
    csrrw sp, sscratch, sp

    # 保存通用寄存器
    sd x1, 1*8(sp)
    sd x3, 3*8(sp)
    # ... x4-x31

    # 保存控制寄存器
    csrr t0, sstatus
    csrr t1, sepc
    sd t0, 32*8(sp)
    sd t1, 33*8(sp)

    # 保存 sp
    csrr t2, sscratch
    sd t2, 2*8(sp)

    # 切换到内核地址空间
    ld t0, 34*8(sp)  # kernel_satp
    ld t1, 35*8(sp)  # trap_handler_va
    ld sp, 36*8(sp)  # kernel_sp
    csrw satp, t0
    sfence.vma

    # 调用 Rust 处理函数
    jr t1
```

**恢复汇编**:
```asm
_restore:
    # 切换到用户地址空间
    csrw satp, a0
    sfence.vma

    # 设置 sscratch
    csrw sscratch, a1
    mv sp, a1

    # 恢复控制寄存器
    ld t0, 32*8(sp)
    ld t1, 33*8(sp)
    csrw sstatus, t0
    csrw sepc, t1

    # 恢复通用寄存器
    ld x1, 1*8(sp)
    ld x3, 3*8(sp)
    # ... x4-x31
    ld sp, 2*8(sp)

    # 返回用户态
    sret
```

#### 3.5.2 Trap 处理

```rust
// kernel/src/trap/mod.rs
pub extern "C" fn trap_handler_inner() -> ! {
    unsafe {
        stvec::write(trap_handler_in_kernel as usize, TrapMode::Direct);
    }
    let mut context = PROCESS_MANAGER.write().get_mut_current_context();
    let scause = scause::read();
    let stval = stval::read();

    match scause.cause() {
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            timer_interrupt_hanlder()
        }
        Trap::Exception(Exception::UserEnvCall) => {
            context.sepc += 4;
            let res = syscall::syscall(context.x[17], [...]);
            context = PROCESS_MANAGER.write().get_mut_current_context();
            context.x[10] = res;
        }
        Trap::Exception(Exception::IllegalInstruction) => {
            panic!("[KERNEL] IllegalInstruction");
        }
        _ => {
            panic!("Unsupported trap {:?}, stval = {:#x}!", scause.cause(), stval);
        }
    }
    jump_restore()
}
```

